<div class="ja">
<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">ビットコイン推定レバレッジ比率(ELR)の推移</text>
  <line x1="80" y1="60" x2="80" y2="280" stroke="#3f3f46" stroke-width="1"/>
  <line x1="80" y1="280" x2="650" y2="280" stroke="#3f3f46" stroke-width="1"/>
  <g font-family="sans-serif" font-size="14">
    <text x="180" y="300" fill="#a1a1aa" text-anchor="middle">6月30日(底値)</text>
